ALGORITHM ComputeDistances(p1, p2)
// p1 = (x1, y1), p2 = (x2, y2)
BEGIN
 dx = |x1 - x2|
 dy = |y1 - y2|

 // Euclidean distance
 euclidean = SQRT(dx*dx + dy*dy)

 // Manhattan distance (city-block)
 manhattan = dx + dy

 // Chebyshev distance (chessboard)
 chebyshev = MAX(dx, dy)

 RETURN euclidean, manhattan, chebyshev
END

ALGORITHM CalculateImageResources(width, height, bitsPerPixel)
BEGIN
 // Total pixels
 totalPixels = width * height

 // Total bits and bytes
 totalBits = totalPixels * bitsPerPixel
 totalBytes = totalBits / 8

 // Storage in different units
 KB = totalBytes / 1024
 MB = KB / 1024

 // Gray levels from bit depth
 grayLevels = 2^bitsPerPixel

 // Example: 1920x1080, 24-bit color
 // totalPixels = 2,073,600
 // totalBytes = 6,220,800 bytes ≈ 5.93 MB

 RETURN totalPixels, totalBytes, KB, MB, grayLevels
END
